        }
    }
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct apcrm_Finding {
    pub text:        String,
    pub replacement: String,
    pub severity:    apcrm_Severity,
    pub mechanism:   apcrm_Mechanism,
    pub category:    apcrm_PhiCategory,
    pub offset:      usize,
    pub length:      usize,
}

