15	//! Dictionary and regex matching — Tier 1 structural patterns, Tier 2 label-anchored, Tier 3 dictionary.
16	
17	use crate::apcrd_dictionaries::apcrd_Dictionaries;
18	use crate::apcrp_parse::{apcrp_Span, apcrp_SpanKind};
19	use regex::Regex;
20	use unicode_segmentation::UnicodeSegmentation;
